int loadData(char *filename,std::vector<Record> &records,std::vector<LatLong> &locations){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;

    /**Main processing **/

    flist = fopen(filename, "r");
	if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        exit(1);
    }
	while(fscanf(flist, "%s\n", dbname) == 1) {
		/**
		* Read in all records of length REC_LENGTH
		* If this is the last file in the filelist, then done
		* else open next file to be read next iteration
		*/
        fp = fopen(dbname, "r");
        if(!fp) {
            fprintf(stderr, "error opening a db: %s\n", dbname);
            // Continue to next file if one fails, or exit depending on desired behavior
            continue;
        }
        // read each record
        char line[REC_LENGTH + 2]; // +2 for potential newline and null terminator
        while(fgets(line, sizeof(line), fp) != NULL){
            Record record;
            LatLong latLong;

            // Ensure the line is long enough to contain the expected data
            if (strlen(line) < LATITUDE_POS + 10) { // LATITUDE_POS + length of lat/lng fields + buffer
                // Skip malformed lines or handle error
                continue;
            }

            strncpy(record.recString, line, REC_LENGTH - 1);
            record.recString[REC_LENGTH - 1] = '\0'; // Ensure null termination

            // parse for lat and long
            char substr[6];

            // Latitude
            strncpy(substr, record.recString + LATITUDE_POS, 5);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Longitude
            strncpy(substr, record.recString + LATITUDE_POS + 5, 5); // Assuming longitude is 5 chars after latitude
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec; // Use a temporary Record struct for swapping
  float tempDist;

  for(i=0;topN > i;i++) {
    minLoc = i;
    for(j=i;numRecords > j;j++) {
      val = distances[j];
      if (distances[minLoc] > val) minLoc = j;
    }
    // swap locations and distances
    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    // add distance to the min we just found
    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (2 > argc) return 1; // error
    strncpy(filename,argv[1],100);
    filename[99] = '\0'; // Ensure null termination
    char flag;

    for(i=1;i<argc;i++) { // Iterate through arguments starting from the second one
      if (argv[i][0] == '-' && strlen(argv[i]) > 1) {// flag
        flag = argv[i][1];
          switch (flag) {
            case 'r': // number of results
              if (i + 1 < argc) {
                *r = atoi(argv[++i]);
              } else return 1; // missing argument
              break;
            case 'l': // lat or lng
              if (i + 1 < argc) {
                if (strcmp(argv[i], "-lat") == 0) { // Check for "-lat" specifically
                    *lat = atof(argv[++i]);
                } else if (strcmp(argv[i], "-lng") == 0) { // Check for "-lng" specifically
                    *lng = atof(argv[++i]);
                } else {
                    return 1; // Unknown flag starting with 'l'
                }
              } else return 1; // missing argument
              break;
            case 'h': // help
              return 1;
            case 'q': // quiet
              *q = 1;
              break;
            case 't': // timing
              *t = 1;
              break;
            case 'p': // platform
              if (i + 1 < argc) {
                *p = atoi(argv[++i]);
              } else return 1; // missing argument
              break;
            case 'd': // device
              if (i + 1 < argc) {
                *d = atoi(argv[++i]);
              } else return 1; // missing argument
              break;
            default:
              // Unknown flag
              return 1;
          }
      } else {
          // If it's not a flag, and it's not the first argument (filename), it's an error
          if (i != 1) return 1;
      }
    }
    if ((0 <= *d && 0 > *p) || (0 <= *p && 0 > *d)) // both p and d must be specified if either are specified
      return 1;
    return 0;
}

